CREATE TRIGGER [dbo].[OrderItemUnitWorkElementHistory_History]ON [dbo].[OrderItemUnitWorkElementHistory]AFTER INSERT, UPDATE, DELETE ASDECLARE @HistoryAction CHAR(1)set @HistoryAction = (SELECT TOP 1 	CASE 		WHEN i.OrderItemUnitWorkElementHistoryId IS NOT NULL AND d.OrderItemUnitWorkElementHistoryId IS NULL THEN 'I' 		WHEN i.OrderItemUnitWorkElementHistoryId IS NOT NULL AND d.OrderItemUnitWorkElementHistoryId IS NOT NULL THEN 'U' 		WHEN i.OrderItemUnitWorkElementHistoryId IS NULL AND d.OrderItemUnitWorkElementHistoryId IS NOT NULL THEN 'D'		ELSE 'NA'	END AS HistoryActionfrom inserted as i	full outer join deleted as d on i.OrderItemUnitWorkElementHistoryId = d.OrderItemUnitWorkElementHistoryId)IF @HistoryAction = 'I' OR @HistoryAction = 'U'BEGIN	INSERT INTO History.dbo_OrderItemUnitWorkElementHistory([OrderItemUnitWorkElementHistoryId], [OrderItemUnitId], [BillOfProcessProcessWorkElementId], [EquipmentId], [WorkElementStatusId], [UserId], [StartDate], [StartDateUtc], [EndDate], [EndDateUtc], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],[HistoryAction])	SELECT [OrderItemUnitWorkElementHistoryId], [OrderItemUnitId], [BillOfProcessProcessWorkElementId], [EquipmentId], [WorkElementStatusId], [UserId], [StartDate], [StartDateUtc], [EndDate], [EndDateUtc], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],@HistoryAction 	FROM insertedENDELSE IF @HistoryAction = 'D'BEGIN	INSERT INTO History.dbo_OrderItemUnitWorkElementHistory([OrderItemUnitWorkElementHistoryId], [OrderItemUnitId], [BillOfProcessProcessWorkElementId], [EquipmentId], [WorkElementStatusId], [UserId], [StartDate], [StartDateUtc], [EndDate], [EndDateUtc], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],[HistoryAction])	SELECT [OrderItemUnitWorkElementHistoryId], [OrderItemUnitId], [BillOfProcessProcessWorkElementId], [EquipmentId], [WorkElementStatusId], [UserId], [StartDate], [StartDateUtc], [EndDate], [EndDateUtc], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],@HistoryAction  	FROM deletedEND